// src/services/api.js - Semua panggilan ke backend RouteAI
import axios from 'axios';

const BASE_URL = process.env.REACT_APP_API_URL || 'http://localhost:5000/api';

// Axios instance utama
const api = axios.create({
  baseURL: BASE_URL,
  timeout: 15000,
  headers: { 'Content-Type': 'application/json' }
});

// Interceptor: tambah token JWT ke setiap request
api.interceptors.request.use((config) => {
  const token = localStorage.getItem('routeai_token');
  if (token) config.headers.Authorization = `Bearer ${token}`;
  return config;
});

// Interceptor: handle 401 → refresh token / redirect login
api.interceptors.response.use(
  (res) => res,
  async (err) => {
    if (err.response?.status === 401 && err.response?.data?.code === 'TOKEN_EXPIRED') {
      try {
        const refresh = localStorage.getItem('routeai_refresh');
        const res = await axios.post(`${BASE_URL}/auth/refresh`, { refreshToken: refresh });
        const newToken = res.data.data.token;
        localStorage.setItem('routeai_token', newToken);
        err.config.headers.Authorization = `Bearer ${newToken}`;
        return api(err.config);
      } catch {
        localStorage.clear();
        window.location.href = '/login';
      }
    }
    return Promise.reject(err);
  }
);

// ============ AUTH ============
export const authAPI = {
  register: (data) => api.post('/auth/register', data),
  login: (identifier, password) => api.post('/auth/login', { identifier, password }),
  loginGoogle: (data) => api.post('/auth/google', data),
  logout: () => api.post('/auth/logout'),
  refreshToken: (refreshToken) => api.post('/auth/refresh', { refreshToken }),
};

// ============ USER ============
export const userAPI = {
  getProfile: () => api.get('/user/profile'),
  updateProfile: (data) => api.put('/user/profile', data),
  addSavedLocation: (data) => api.post('/user/saved-locations', data),
  deleteSavedLocation: (id) => api.delete(`/user/saved-locations/${id}`),
};

// ============ ROUTE ============
export const routeAPI = {
  search: (query) => api.get('/route/search', { params: { q: query } }),
  reverse: (lat, lng) => api.get('/route/reverse', { params: { lat, lng } }),
  calculate: (origin, destination, options = {}) =>
    api.post('/route/calculate', { origin, destination, ...options }),
  optimizeStops: (origin, stops, vehicle) =>
    api.post('/route/optimize-stops', { origin, stops, vehicle }),
  shareTrip: (tripId) => api.post(`/route/share/${tripId}`),
  getLiveShare: (token) => api.get(`/route/live/${token}`),
};

// ============ AI ============
export const aiAPI = {
  chat: (message, history, context) =>
    api.post('/ai/chat', { message, history, context }),
  analyzeRoute: (route, origin, destination, vehicle) =>
    api.post('/ai/analyze-route', { route, origin, destination, vehicle }),
  predictTraffic: (area, timeRange) =>
    api.post('/ai/predict-traffic', { area, timeRange }),
  driverRecommendation: (currentLocation, currentEarnings) =>
    api.post('/ai/driver-recommendation', { currentLocation, currentEarnings }),
  ecoScore: (distance, routeType, vehicle) =>
    api.post('/ai/eco-score', { distance, routeType, vehicle }),
};

// ============ WEATHER ============
export const weatherAPI = {
  get: (lat, lng) => api.get('/weather', { params: { lat, lng } }),
};

// ============ TRAFFIC ============
export const trafficAPI = {
  get: () => api.get('/traffic'),
};

// ============ DRIVER ============
export const driverAPI = {
  updateStatus: (isOnline, lat, lng) =>
    api.patch('/driver/status', { isOnline, lat, lng }),
  getDemand: () => api.get('/driver/demand'),
  getEarnings: () => api.get('/driver/earnings'),
};

// ============ TRIP ============
export const tripAPI = {
  getHistory: (page = 1) => api.get('/trip/history', { params: { page } }),
  getDetail: (id) => api.get(`/trip/${id}`),
  startTrip: (id) => api.patch(`/trip/${id}/start`),
  completeTrip: (id, stats) => api.patch(`/trip/${id}/complete`, stats),
  rateTrip: (id, score, comment) => api.post(`/trip/${id}/rate`, { score, comment }),
};

// ============ SOS ============
export const sosAPI = {
  trigger: (lat, lng, tripId) => api.post('/sos/trigger', { lat, lng, tripId }),
  updateContacts: (contacts) => api.put('/sos/contacts', { contacts }),
};

// ============ NOMINATIM langsung (untuk autocomplete cepat) ============
export const geocodeSearch = async (query, limit = 6) => {
  try {
    const res = await axios.get('https://nominatim.openstreetmap.org/search', {
      params: {
        format: 'json', q: query + ', Indonesia',
        limit, addressdetails: 1, countrycodes: 'id', 'accept-language': 'id'
      },
      timeout: 6000
    });
    return res.data.map(r => ({
      id: r.place_id,
      name: r.display_name.split(',')[0],
      address: r.display_name.split(',').slice(1, 3).join(',').trim(),
      lat: parseFloat(r.lat),
      lng: parseFloat(r.lon)
    }));
  } catch { return []; }
};

// ============ OSRM langsung (routing cepat) ============
export const calculateRoute = async (originLng, originLat, destLng, destLat) => {
  try {
    const OSRM = process.env.REACT_APP_OSRM_URL || 'https://router.project-osrm.org';
    const res = await axios.get(
      `${OSRM}/route/v1/driving/${originLng},${originLat};${destLng},${destLat}`,
      { params: { overview: 'full', geometries: 'geojson', steps: true }, timeout: 10000 }
    );
    return res.data.routes?.[0] || null;
  } catch { return null; }
};

export default api;
